const { IMPORT_TYPES } = require('../../../../constants/islands');

/**
 * @typedef {{ localKey: string, importKey: string | undefined }} ImportKeysCollection
 * @typedef {{ node: any | undefined, namedExport: boolean | undefined }} ImportInfo
 * @typedef {{ importKeys: ImportKeysCollection, info: ImportInfo, nodesWithProperty: string[] | undefined }} NodeData
 */

/**
 * @param {import('.').NodesManifest} destination
 * @param {ImportKeysCollection} importKeys
 * @param {ImportInfo} importInfo
 */
const assignNodeValuesToDestinationByKeys = (
  destination,
  { localKey, importKey },
  { node, namedExport },
) => {
  if (!destination[localKey]) {
    destination[localKey] = {};
  }

  const key =
    importKey === IMPORT_TYPES.DEFAULT
      ? null
      : importKey || destination[localKey].importName || null;
  const nodeNamedExport =
    typeof namedExport === 'boolean'
      ? namedExport
      : destination[localKey].namedExport;

  let newNode = destination[localKey]?.node || null;

  if (node) {
    if (newNode) {
      newNode.push(node);
    } else {
      newNode = [node];
    }
  }

  Object.assign(destination[localKey], {
    key,
    importName: importKey || key,
    node: newNode,
    namedExport: nodeNamedExport,
  });

  if (!importKey || importKey === localKey || (importKey && !key)) {
    return;
  }

  if (!destination[importKey]) {
    destination[importKey] = {};
  }

  destination[importKey] = {
    importName: key,
    node: newNode,
    namedExport: nodeNamedExport,
  };
};

/**
 * @param {import('.').NodesManifest} destination
 * @param {string[]} componentKeys
 */
const assignNodesWithPropertyValuesToDestinationByComponentKeys = (
  destination,
  componentKeys,
) => {
  componentKeys.forEach((componentKey) => {
    Object.keys(destination).forEach((key) => {
      if (!key.startsWith(`${componentKey}-`)) {
        return;
      }

      Object.assign(destination[key], {
        importName: destination[componentKey].importName,
        key: destination[componentKey].key,
        namedExport: destination[componentKey].namedExport,
      });
    });
  });
};

/**
 * @param {import('.').NodesManifest} destination
 * @param {NodeData[]} nodesData
 */
const assignNodeValuesToDestination = (destination, nodesData) => {
  nodesData.forEach(({ importKeys, info, nodesWithProperty }) => {
    assignNodeValuesToDestinationByKeys(destination, importKeys, info);

    assignNodesWithPropertyValuesToDestinationByComponentKeys(
      destination,
      nodesWithProperty || [],
    );
  });
};

module.exports = {
  assignNodeValuesToDestinationByKeys,
  assignNodesWithPropertyValuesToDestinationByComponentKeys,
  assignNodeValuesToDestination,
};
